// REPLACE: aquí debes llamar a Whisper / STT real (HTTP Request con multipart/form-data)
// Por ahora placeholder que copia un texto simulado
items[0].json.transcription = 'TRANSCRIBED TEXT PLACEHOLDER - reemplazar por resultado real de STT';
return items;

// Compose final text: si tenemos transcription usamos eso, si no usamos messageText
const msg = $json["transcription"] || $json["messageText"] || '';
items[0].json.final_text = msg;
return items;

// Parse orchestration output (esperamos JSON en choices[0].message.content)
const raw = $json["body"] || $json["choices"]?.[0]?.message?.content || $json["choices"]?.[0]?.text || null;
let parsed = {};
try {
  // algunos modelos devuelven el JSON sin comillas adecuadas; asumimos JSON válido
  const candidate = typeof raw === 'string' ? raw.trim() : raw;
  parsed = JSON.parse(candidate);
} catch (e) {
  // fallback: intentar extraer primer bloque JSON
  const s = (raw || '').toString();
  const m = s.match(/\{[\s\S]*\}/);
  if (m) {
    try { parsed = JSON.parse(m[0]); } catch(err) { parsed = {error: 'no-json', raw: s}; }
  } else parsed = {error: 'no-json', raw: s};
}
items[0].json.orchestration = parsed;
// expand into multiple properties para que cada agente reciba el mismo payload
return items;

// Placeholder: crear evento en Google Calendar
const o = $json.orchestration || {};
if (!o.calendar) {
  return [];
}
// En producción reemplaza por nodo Google Calendar: create event usando o.calendar.*
items[0].json.calendarResult = { status: 'placeholder_created', details: o.calendar };
return items;

// Placeholder: enviar email (SendGrid / SMTP). Reemplaza por nodo SendGrid o HTTP Request con tu API
const o = $json.orchestration || {};
if (!o.email) return [];
items[0].json.emailResult = { status: 'placeholder_sent', details: o.email };
return items;

// Placeholder: actualizar contacto en Airtable/CRM
const o = $json.orchestration || {};
if (!o.contact) return [];
items[0].json.contactResult = { status: 'placeholder_updated', details: o.contact };
return items;

// Placeholder: crear contenido (texto, caption, tags). Reemplaza por OpenAI text generation y por saver nodes
const o = $json.orchestration || {};
if (!o.createContent) return [];
items[0].json.content = { title: 'TITLE_PLACEHOLDER', body: 'BODY_PLACEHOLDER based on: '+JSON.stringify(o.createContent) };
return items;

// Placeholder: guardar contenido en Drive / S3
if (!$json.content) return [];
items[0].json.saved = { id: 'placeholder_file_id', path: '/drive/...'};
return items;

// Placeholder: publicar en canal (Telegram, X, Facebook). Reemplaza por HTTP Request a cada API o por nodos oficiales.
if (!$json.saved && !$json.content) return [];
items[0].json.published = { channels: ['telegram','x'], status: 'placeholder_ok' };
return items;

// Final logging: guarda todo en una hoja / airtable
items[0].json.log = { time: new Date().toISOString(), orchestration: $json.orchestration || null };
return items;
